python3 - <<'PY'
import sqlite3
conn=sqlite3.connect('database.db')
cur=conn.cursor()
for g in [1,2,3]:
    print(f'GROUP {g} main_cat samples:')
    try:
        for row in cur.execute(f"SELECT main_cat, COUNT(*) c FROM items_g{g} GROUP BY main_cat ORDER BY c DESC LIMIT 10"):
            print(row)
    except Exception as e:
        print('err',e)
    print(f'GROUP {g} taxonomy samples:')
    tables=[r[0] for r in cur.execute("SELECT name FROM sqlite_master WHERE type='table'").fetchall()]
    tax=f"taxn_g{g}"
    if tax in tables:
        for row in cur.execute(f"SELECT cat_nm, COUNT(*) c FROM {tax} GROUP BY cat_nm ORDER BY c DESC LIMIT 15"):
            print(row)
    print(f'GROUP {g} title samples:')
    for row in cur.execute(f"SELECT ref_id, ttl, main_cat, avg_rtg FROM items_g{g} LIMIT 5"):
        print(row)
    print()
PY

