import sqlite3, datetime
conn=sqlite3.connect('database.db')
cur=conn.cursor()

def year_from_numeric(ts):
    ts=int(ts)
    # choose plausible interpretation among seconds, milliseconds, microseconds
    candidates=[]
    for div,name in [(1,'s'),(1000,'ms'),(1_000_000,'us')]:
        try:
            y=datetime.datetime.utcfromtimestamp(ts/div).year
            if 1990 <= y <= 2100:
                candidates.append((y,name))
        except:
            pass
    # prefer seconds, then ms, then us if plausible
    if candidates:
        return candidates[0][0]
    return None

total=0
for g in [1,2,3]:
    items=f'items_g{g}'; fdbk=f'fdbk_g{g}'
    rows=cur.execute(f"""
        SELECT f.ts FROM {fdbk} f
        JOIN {items} i ON f.ref_id=i.ref_id
        WHERE i.main_cat='All Electronics' AND f.ts IS NOT NULL
    """)
    cnt=0
    for (ts,) in rows:
        y=None
        if g==3:
            try:
                y=int(str(ts)[:4])
            except:
                y=None
        else:
            y=year_from_numeric(ts)
        if y is not None and y >= 2031:
            cnt += 1
    print('g',g,cnt)
    total += cnt
print('TOTAL', total)
