SELECT MIN(prc), MAX(prc) FROM items_g1 WHERE main_cat='Musical Instruments' AND prc IS NOT NULL;
SELECT '---';
SELECT MIN(prc), MAX(prc) FROM items_g3 WHERE main_cat='Musical Instruments' AND prc IS NOT NULL;"

