arguments.command:
sqlite3 database.db "
WITH office AS (
  SELECT ref_id FROM items_g1 WHERE main_cat='Office Products'
),
years AS (
  SELECT f.ref_id, CAST(strftime('%Y', f.ts/1000, 'unixepoch') AS INTEGER) AS yr
  FROM fdbk_g1 f JOIN office o ON f.ref_id=o.ref_id
)
SELECT COUNT(*) FROM (
  SELECT ref_id FROM years WHERE yr < 2031 GROUP BY ref_id HAVING COUNT(DISTINCT yr) >= 5
);
"

sqlite3 database.db "
WITH office AS (
  SELECT ref_id FROM items_g2 WHERE main_cat='Office Products'
),
years AS (
  SELECT f.ref_id, CAST(strftime('%Y', f.ts, 'unixepoch') AS INTEGER) AS yr
  FROM fdbk_g2 f JOIN office o ON f.ref_id=o.ref_id
)
SELECT COUNT(*) FROM (
  SELECT ref_id FROM years WHERE yr < 2031 GROUP BY ref_id HAVING COUNT(DISTINCT yr) >= 5
);
SELECT '---';
WITH office AS (
  SELECT ref_id FROM items_g3 WHERE main_cat='Office Products'
),
years AS (
  SELECT f.ref_id, CAST(substr(f.ts,1,4) AS INTEGER) AS yr
  FROM fdbk_g3 f JOIN office o ON f.ref_id=o.ref_id
)
SELECT COUNT(*) FROM (
  SELECT ref_id FROM years WHERE yr < 2031 GROUP BY ref_id HAVING COUNT(DISTINCT yr) >= 5
);
"

