arguments.command:
for g in 1 2 3; do echo "=== g$g All Electronics review counts by rtg (verified, non-empty body) ==="; 
if [ $g -eq 2 ]; then v="f.vrf='true'"; else v="f.vrf=1"; fi
sqlite3 database.db "SELECT f.rtg, COUNT(*), ROUND(AVG(LENGTH(f.body)),2) FROM fdbk_g$g f JOIN items_g$g i ON f.ref_id=i.ref_id WHERE i.main_cat='All Electronics' AND $v AND f.body IS NOT NULL AND TRIM(f.body)<>'' AND f.rtg IN (1.0,5.0) GROUP BY f.rtg;"; done

