sqlite3 database.db "SELECT DISTINCT main_cat FROM items_g1;
SELECT '---';
SELECT DISTINCT main_cat FROM items_g2;
SELECT '---';
SELECT DISTINCT main_cat FROM items_g3;"

sqlite3 database.db "SELECT DISTINCT cat_nm FROM taxn_g1 WHERE cat_nm LIKE '%lectronic%';
SELECT '---';
SELECT DISTINCT cat_nm FROM taxn_g2 WHERE cat_nm LIKE '%lectronic%';"

sqlite3 database.db "SELECT MIN(prc), MAX(prc), AVG(prc) FROM items_g1 WHERE prc IS NOT NULL;
SELECT MIN(prc), MAX(prc), AVG(prc), MIN(prc_usd), MAX(prc_usd), AVG(prc_usd) FROM items_g2 WHERE prc IS NOT NULL;
SELECT MIN(prc), MAX(prc), AVG(prc) FROM items_g3 WHERE prc IS NOT NULL;"

sqlite3 database.db "SELECT COUNT(*) FROM items_g1 i1 JOIN items_g2 i2 ON i1.ref_id=i2.ref_id;
SELECT COUNT(*) FROM items_g1 i1 JOIN items_g3 i3 ON i1.ref_id=i3.ref_id;
SELECT COUNT(*) FROM items_g2 i2 JOIN items_g3 i3 ON i2.ref_id=i3.ref_id;"

