arguments.command:
sqlite3 database.db "
WITH offc AS (
  SELECT ref_id FROM items_g1 WHERE main_cat='Office Products'
),
years AS (
  SELECT ref_id, CAST(strftime('%Y', ts/1000, 'unixepoch') AS INT) AS y
  FROM fdbk_g1 WHERE ref_id IN offc
)
SELECT COUNT(*) FROM (
  SELECT ref_id FROM years WHERE y < 2031 GROUP BY ref_id HAVING COUNT(DISTINCT y) >= 5
);
"

sqlite3 database.db "
WITH offc AS (
  SELECT ref_id FROM items_g2 WHERE main_cat='Office Products'
),
years AS (
  SELECT ref_id, CAST(strftime('%Y', ts, 'unixepoch') AS INT) AS y
  FROM fdbk_g2 WHERE ref_id IN offc
)
SELECT COUNT(*) FROM (
  SELECT ref_id FROM years WHERE y < 2031 GROUP BY ref_id HAVING COUNT(DISTINCT y) >= 5
);
SELECT '---';
WITH offc AS (
  SELECT ref_id FROM items_g3 WHERE main_cat='Office Products'
),
years AS (
  SELECT ref_id, CAST(substr(ts,1,4) AS INT) AS y
  FROM fdbk_g3 WHERE ref_id IN offc AND ts IS NOT NULL
)
SELECT COUNT(*) FROM (
  SELECT ref_id FROM years WHERE y < 2031 GROUP BY ref_id HAVING COUNT(DISTINCT y) >= 5
);
"

sqlite3 database.db "
WITH offc AS (
  SELECT ref_id FROM items_g2 WHERE main_cat='Office Products'
),
years AS (
  SELECT ref_id, CAST(strftime('%Y', CASE WHEN ts > 10000000000 THEN ts/1000 ELSE ts END, 'unixepoch') AS INT) AS y
  FROM fdbk_g2 WHERE ref_id IN offc
)
SELECT COUNT(*) FROM (
  SELECT ref_id FROM years WHERE y < 2031 GROUP BY ref_id HAVING COUNT(DISTINCT y) >= 5
);
"

