sqlite3 database.db "
WITH stats AS (
  SELECT ref_id, COUNT(*) rc, AVG(rtg) ar FROM fdbk_g2 GROUP BY ref_id
)
SELECT COUNT(*) FROM items_g2 i JOIN stats s ON i.ref_id=s.ref_id
WHERE i.main_cat='All Electronics' AND i.prc_usd>50 AND s.rc>=5 AND s.ar<3.0;
