arguments.command:
python3 << 'EOF'
import sqlite3
from datetime import datetime,timezone
con=sqlite3.connect('database.db')
cur=con.cursor()

def years(rows,kind):
    yc={}
    for (ts,) in rows:
        if ts is None or ts=='' : continue
        if kind=='g1':
            y=datetime.fromtimestamp(ts/1000,timezone.utc).year
        elif kind=='g2':
            y=datetime.fromtimestamp(ts,timezone.utc).year
        else:
            y=int(str(ts)[:4])
        yc[y]=yc.get(y,0)+1
    return yc

# raw, no correction, all office products
g1=years(cur.execute("SELECT f.ts FROM fdbk_g1 f JOIN items_g1 i ON f.ref_id=i.ref_id WHERE i.main_cat='Office Products'"),'g1')
g2=years(cur.execute("SELECT f.ts FROM fdbk_g2 f JOIN items_g2 i ON f.ref_id=i.ref_id WHERE i.main_cat='Office Products'"),'g2')
g3=years(cur.execute("SELECT f.ts FROM fdbk_g3 f JOIN items_g3 i ON f.ref_id=i.ref_id WHERE i.main_cat='Office Products'"),'g3')
for name,d in [('g1',g1),('g2',g2),('g3',g3)]:
    hi={y:c for y,c in d.items() if y>=2031}
    print(name,'years>=2031 (raw):',hi, 'max year:',max(d) if d else None)
EOF

