sqlite3 database.db "SELECT COUNT(*) FROM (SELECT ref_id FROM items_g1 WHERE main_cat='Office Products' INTERSECT SELECT ref_id FROM items_g2 WHERE main_cat='Office Products');
SELECT COUNT(*) FROM (SELECT ref_id FROM items_g1 WHERE main_cat='Office Products' INTERSECT SELECT ref_id FROM items_g3 WHERE main_cat='Office Products');
SELECT COUNT(*) FROM (SELECT ref_id FROM items_g2 WHERE main_cat='Office Products' INTERSECT SELECT ref_id FROM items_g3 WHERE main_cat='Office Products');"

sqlite3 database.db "
SELECT 'g1', COUNT(*) FROM (SELECT f.ref_id FROM fdbk_g1 f JOIN items_g1 i ON f.ref_id=i.ref_id WHERE i.main_cat='Office Products' AND CAST(strftime('%Y', f.ts/1000, 'unixepoch') AS INTEGER)<2031 GROUP BY f.ref_id HAVING COUNT(DISTINCT strftime('%Y', f.ts/1000, 'unixepoch'))>=5);
SELECT 'g2', COUNT(*) FROM (SELECT f.ref_id FROM fdbk_g2 f JOIN items_g2 i ON f.ref_id=i.ref_id WHERE i.main_cat='Office Products' AND CAST(strftime('%Y', f.ts, 'unixepoch') AS INTEGER)<2031 GROUP BY f.ref_id HAVING COUNT(DISTINCT strftime('%Y', f.ts, 'unixepoch'))>=5);
SELECT 'g3', COUNT(*) FROM (SELECT f.ref_id FROM fdbk_g3 f JOIN items_g3 i ON f.ref_id=i.ref_id WHERE i.main_cat='Office Products' AND CAST(substr(f.ts,1,4) AS INTEGER)<2031 GROUP BY f.ref_id HAVING COUNT(DISTINCT substr(f.ts,1,4))>=5);
"

