arguments.command:
sqlite3 database.db "
-- g1: standard is ms, so 15-digit /1000 -> huge future year
SELECT ts, strftime('%Y', datetime(ts/1000,'unixepoch')) FROM fdbk_g1 WHERE length(CAST(ts AS TEXT))=15 LIMIT 3;
SELECT '---';
-- g2: standard is seconds, 12-digit as seconds -> future
SELECT ts, strftime('%Y', datetime(ts,'unixepoch')) FROM fdbk_g2 WHERE length(CAST(ts AS TEXT))=12 LIMIT 3;"

