arguments.command:
sqlite3 database.db "
SELECT COUNT(*) FROM fdbk_g1 f JOIN items_g1 i ON f.ref_id=i.ref_id WHERE i.main_cat='All Electronics' AND f.ts>=strftime('%s','2021-10-01')*1000 AND f.ts<strftime('%s','2022-01-01')*1000;
SELECT '---';
SELECT COUNT(*) FROM fdbk_g2 f JOIN items_g2 i ON f.ref_id=i.ref_id WHERE i.main_cat='All Electronics' AND f.ts>=strftime('%s','2021-10-01') AND f.ts<strftime('%s','2022-01-01');
SELECT '---';
SELECT COUNT(*) FROM fdbk_g3 f JOIN items_g3 i ON f.ref_id=i.ref_id WHERE i.main_cat='All Electronics' AND f.ts>='2021-10-01' AND f.ts<'2022-01-01';
"

